export const getGetEmergencyWorkersUrl = (
  params?: GetEmergencyWorkersParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/emergency/workers?${stringifiedParams}`
    : `/api/emergency/workers`;
};

export const getEmergencyWorkers = async (
  params?: GetEmergencyWorkersParams,
  options?: RequestInit,
): Promise<WorkersListResponse> => {
  return customFetch<WorkersListResponse>(getGetEmergencyWorkersUrl(params), {
    ...options,
    method: "GET",
  });
};

